  /**
   * Find existing customer by email or phone, or create new one
   */
  private async findOrCreateCustomer(
    customerInput: { firstName: string; lastName: string; phone?: string; email?: string },
    ownerId: string,
    createdBy: string,
  ) {
    // Try to find existing customer by email or phone
    let existingCustomer: Customer | null = null;

    if (customerInput.email) {
      existingCustomer = await this.customerRepo.findOne({
        where: { email: customerInput.email, ownerId },
      });
    }

    if (!existingCustomer && customerInput.phone) {
      existingCustomer = await this.customerRepo.findOne({
        where: { phone: customerInput.phone, ownerId },
      });
    }

    // If customer exists, return it
    if (existingCustomer) {
      return existingCustomer;
    }

    // Otherwise, create new customer
    return this.bookingRepo.insert({
      ...customerInput,
      ownerId,
      createdBy,
    });
  }

