    const contactCustomer = await this.findOrCreateCustomer(contact, ownerId, createdBy);
    // TODO:Create booking
  }

  /**
   * Find booking by ID or code
   */
  async find(idOrCode: string) {
    const isNumeric = /^\d+$/.test(idOrCode);

    const booking = await this.bookingRepo.findOne({
      where: isNumeric ? { id: parseInt(idOrCode, 10) } : { code: idOrCode },
      relations: [
        'bookingCustomer',
        'bookingRooms',
        'bookingRooms.room',
        'bookingRooms.hotel',
        'bookingRooms.customers',
        'bookingRooms.bookingRoomSurchargeFees',
        'bookingRooms.bookingRoomSurchargeFees.surchargeFeeSetting',
      ],
    });

    if (!booking) throw new NotFoundError(ErrorCode.BOOKING_NOT_FOUND);
    return booking;
  }

  async findAll(params: BookingQueryParamsInput) {
    return this.bookingRepo.findAll(params);
  }

  /**
   * Cập nhật trạng thái có thể đặt phòng hoặc không thể đặt phòng
   * @param idOrCode - Booking ID hoặc code
   */
  async updateBooking(idOrCode: string, updateDto: BookingUpdateInput) {
    // Tìm booking
    const booking = await this.bookingRepo.findOne({
      where: [
        {
          id: parseInt(idOrCode, 10),
          status: BookingStatus.RESERVED,
        },
        {
          code: idOrCode,
          status: BookingStatus.RESERVED,
        },
      ],
    });

    if (!booking) throw new NotFoundError(ErrorCode.BOOKING_NOT_FOUND);

    if (![BookingStatus.CANCELLED, BookingStatus.PENDING_PAYMENT].includes(updateDto.status)) {
      throw new BusinessLogicError(ErrorCode.INVALID_STATUS_TRANSITION);
    }

    // Nếu chuyển sang PENDING_PAYMENT, set thời gian hết hạn thanh toán (30 phút)
    const updateData = {
      status: updateDto.status,
      updatedBy: updateDto.updatedBy,
      paymentDeadline: updateDto.status === BookingStatus.PENDING_PAYMENT ? dayjs().add(30, 'minutes') : null,
    };

    return this.bookingRepo.updateById(booking.id, updateData);
  }

  /**
   * Tự động chuyển các booking PENDING_PAYMENT quá hạn sang EXPIRED
   * Method này nên được gọi bởi một cron job định kỳ
   */
  async expireOverduePayments() {
    const now = new Date();

    // Tìm các booking PENDING_PAYMENT đã quá hạn
    const overdueBookings = await this.bookingRepo
      .createQueryBuilder('booking')
      .where('booking.status = :status', { status: BookingStatus.PENDING_PAYMENT })
      .andWhere('booking.paymentDeadline < :now', { now })
      .getMany();

    // Cập nhật trạng thái sang EXPIRED
    await this.bookingRepo.updateMany(
      overdueBookings.map(b => b.id),
      { status: BookingStatus.EXPIRED },
    );

    return overdueBookings;
  }
}

