import { Inject, Service } from 'typedi';
import { DataSource } from 'typeorm';

import { BedType } from '@Enums/Room';

import { Room } from '@Entities/Room';
import { File } from '@Entities/File';

import { BaseOrmRepository } from '@Repositories/BaseOrmRepository';

export interface BasicRoomInfo {
  id: number;
  code: string;
  localName: string;
  globalName: string;
  maxCapacity: number;
  maxAdults: number;
  maxChildren: number;
  area: number | null;
  bedType: BedType | null;
  isBreakfastIncluded: boolean;
  files: File[];
}

@Service()
export class RoomRepository extends BaseOrmRepository<Room> {
  constructor(@Inject('dataSource') dataSource: DataSource) {
    super(dataSource, Room);
  }

  async findByHotel(hotelId: number) {
    return this.repo.find({
      where: { hotel: { id: hotelId } },
      relations: ['hotel'],
    });
  }

  async findAvailableRooms(hotelId: number) {
    return this.repo.find({
      where: {
        hotel: { id: hotelId },
      },
      relations: ['hotel'],
    });
  }

  async findByHotelIds(hotelIds: number[]) {
    const qb = this.repo
      .createQueryBuilder('room')
      .leftJoin('room.hotel', 'hotel')
      .where('hotel.id IN (:...hotelIds)', { hotelIds });

    return qb.getMany();
  }

  async findBasicsWithFiles(roomIds: number[]): Promise<BasicRoomInfo[]> {
    if (!roomIds.length) return [];
    const qb = this.repo
      .createQueryBuilder('room')
      .leftJoin('room.files', 'files')
      .select([
        'room.id AS id',
        'room.code AS code',
        'room.localName AS "localName"',
        'room.globalName AS "globalName"',
        'room.maxCapacity AS "maxCapacity"',
        'room.maxAdults AS "maxAdults"',
        'room.maxChildren AS "maxChildren"',
        'room.area AS area',
        'room.bedType AS "bedType"',
        'room.isBreakfastIncluded AS "isBreakfastIncluded"',
        `COALESCE(
          jsonb_agg(
            DISTINCT jsonb_build_object(
              'id', files.id,
              'fileUrl', files."fileUrl",
              'title', files.title,
              'description', files.description
            )
          ) FILTER (WHERE files.id IS NOT NULL),
          '[]'::jsonb
        ) AS files`,
      ])
      .where('room.id IN (:...roomIds)', { roomIds })
      .groupBy('room.id');

    const rows = await qb.getRawMany();
    return rows.map(row => ({
      id: Number(row.id),
      code: row.code,
      localName: row.localName,
      globalName: row.globalName,
      maxCapacity: Number(row.maxCapacity),
      maxAdults: Number(row.maxAdults),
      maxChildren: Number(row.maxChildren),
      area: row.area !== null ? Number(row.area) : null,
      bedType: row.bedType ?? null,
      isBreakfastIncluded: !!row.isBreakfastIncluded,
      files: (() => {
        const raw = typeof row.files === 'string' ? JSON.parse(row.files) : row.files ?? [];
        if (!Array.isArray(raw)) return [];
        return raw;
      })(),
    }));
  }
}

