import { Inject, Service } from 'typedi';
import { DataSource } from 'typeorm';
import dayjs from 'dayjs';

import { removeAccents } from '@Libs/env/utils';

import { HotelStatus } from '@Enums/Hotel';

import { Hotel } from '@Entities/Hotel';

import { BaseOrmRepository } from '@Repositories/BaseOrmRepository';

@Service()
export class HotelRepository extends BaseOrmRepository<Hotel> {
  constructor(@Inject('dataSource') dataSource: DataSource) {
    super(dataSource, Hotel);
  }

  async findByCode(code: string) {
    return this.repo.findOne({ where: { code } });
  }

  async findWithRelations(id: number) {
    return this.repo.findOne({
      where: { id },
      relations: [
        'files',
        'image',
        'rooms',
        'amenities',
        'ward',
        'ward.district',
        'ward.district.city',
        'ward.district.city.country',
        'ward.city',
        'ward.city.country',
      ],
    });
  }

  async suggestHotels(
    q: string,
    cityId?: number,
    lat?: number,
    lng?: number,
    limitCount: number = 10,
    cursorScore?: number,
    cursorId?: number,
  ) {
    const query = `
      SELECT * FROM suggest_hotels(
        $1::text,
        $2::int,
        $3::double precision,
        $4::double precision,
        $5::int,
        $6::double precision,
        $7::int
      )
    `;

    const params = [q, cityId || null, lat || null, lng || null, limitCount, cursorScore || null, cursorId || null];

    const result = await this.dataSource.query(query, params);
    return result;
  }

  async fullTextSearch(q: string, limitCount: number = 10) {
    const likePattern = `%${removeAccents(q)}%`;
    const tsVector = `to_tsvector('simple', unaccent(coalesce(h."localName",'') || ' ' || coalesce(h."globalName",'') || ' ' || coalesce(h.code,'')))`;
    const tsQuery = `plainto_tsquery('simple', unaccent($1))`;
    const likeMatch = `(unaccent(h."localName") ILIKE $3 OR h."globalName" ILIKE $3)`;
    const sql = `
      SELECT h.*,
      (SELECT COUNT(*) FROM room r WHERE r."hotelId" = h.id) AS "totalRooms",
            concat_ws(', ', 
              h.star || ' sao',
              h.address, 
              w.name,
              d.name,
              COALESCE(w_city.name, d_city.name)
            )::text AS "subTitle",
      GREATEST(
        ts_rank_cd(
          ${tsVector},
          ${tsQuery}
        ),
        CASE
          WHEN ${likeMatch} THEN 0.001
          ELSE 0
        END
      ) AS score
      FROM hotel h
          LEFT JOIN geo_ward w ON w.id = h."wardId"
          LEFT JOIN geo_district d ON d.id = w."districtId"
          LEFT JOIN geo_city d_city ON d_city.id = d."cityId"
          LEFT JOIN geo_city w_city ON w_city.id = w."cityId"
      WHERE 
        h.status = $2
        AND (${tsVector} @@ ${tsQuery}
        OR ${likeMatch})
      ORDER BY score DESC,
      h.star DESC,
      h."localName" ASC
      LIMIT $4
    `;
    const rows = await this.dataSource.query(sql, [q, HotelStatus.ACTIVE, likePattern, limitCount]);
    return rows as Array<Hotel & { score: number; totalRooms: number; subTitle: string }>;
  }

  async searchHotel(params: {
    checkInDate?: Date;
    checkOutDate?: Date;
    adults?: number;
    children?: number;
    room?: number;
    city?: string;
    page?: number;
    size?: number;
    searchText?: string;
    sortBy?: string;
    sortDirection?: 'ASC' | 'DESC';
    ownerId?: string;
  }) {
    const {
      checkInDate,
      checkOutDate,
      adults,
      children,
      city,
      page = 1,
      size = 10,
      searchText,
      sortBy = 'createdAt',
      sortDirection = 'DESC',
      ownerId,
    } = params;

    // Validate sortBy to prevent SQL injection and invalid column errors
    const allowedSortFields = [
      'id',
      'code',
      'localName',
      'globalName',
      'star',
      'area',
      'address',
      'createdAt',
      'updatedAt',
    ];
    const validSortBy = allowedSortFields.includes(sortBy) ? sortBy : 'createdAt';

    const today = dayjs().startOf('day').format('YYYY-MM-DD');
    const checkInStr = checkInDate ? dayjs(checkInDate).format('YYYY-MM-DD') : null;
    const checkOutStr = checkOutDate ? dayjs(checkOutDate).format('YYYY-MM-DD') : null;

    const promotionJoinCondition = `
      promotions."isActive" = true
      AND TO_DATE(promotions."bookingDate"->>'startDate', 'YYYY-MM-DD') <= :today
      AND TO_DATE(promotions."bookingDate"->>'endDate', 'YYYY-MM-DD') >= :today
      AND (
        :checkInDate::date IS NULL
        OR TO_DATE(promotions."stayDate"->>'endDate', 'YYYY-MM-DD') >= :checkInDate::date
      )
      AND (
        :checkOutDate::date IS NULL
        OR TO_DATE(promotions."stayDate"->>'startDate', 'YYYY-MM-DD') <= :checkOutDate::date
      )
    `;

    const qb = this.createQueryBuilder('hotel')
      .leftJoinAndSelect('hotel.image', 'image')
      .leftJoinAndSelect('hotel.amenities', 'amenities')
      .leftJoinAndSelect('hotel.surchargeFeeSettings', 'surchargeFeeSettings')
      .leftJoinAndSelect('hotel.promotions', 'promotions', promotionJoinCondition, {
        today,
        checkInDate: checkInStr,
        checkOutDate: checkOutStr,
      })
      .leftJoinAndSelect('promotions.rooms', 'promotionRooms')
      .leftJoinAndSelect('hotel.rooms', 'rooms')
      .leftJoinAndSelect('rooms.priceSettings', 'priceSettings', '"priceSettings"."isActive" = true');
    // .leftJoinAndSelect('hotel.ward', 'ward')
