      .leftJoinAndSelect('bookingRooms.hotel', 'hotel')
      .leftJoinAndSelect('bookingRooms.customers', 'customers')
      .leftJoinAndSelect('bookingRooms.bookingRoomSurchargeFees', 'bookingRoomSurchargeFees')
      .leftJoinAndSelect('bookingRoomSurchargeFees.surchargeFeeSetting', 'surchargeFeeSetting');

    if (checkInFrom) {
      const checkInStart = getUtcTime(checkInFrom);
      queryBuilder.andWhere('bookingRooms.checkInDate >= :start', { start: checkInStart });
