    if (checkInTo) {
      const checkInEnd = getUtcTime(checkInTo);
      queryBuilder.andWhere('bookingRooms.checkInDate < :end', { end: checkInEnd });
    }

    if (checkOutFrom) {
      const checkOutStart = getUtcTime(checkOutFrom);
      queryBuilder.andWhere('bookingRooms.checkOutDate >= :start', { start: checkOutStart });
    }

    if (checkOutTo) {
      const checkOutEnd = getUtcTime(checkOutTo);
      queryBuilder.andWhere('bookingRooms.checkOutDate < :end', { end: checkOutEnd });
    }

    if (createdFrom) {
      const createdFromStart = getUtcTime(createdFrom);
      queryBuilder.andWhere('booking.createdAt >= :start', { start: createdFromStart });
    }

    if (createdTo) {
      const createdToEnd = getUtcTime(createdTo);
      queryBuilder.andWhere('booking.createdAt < :end', { end: createdToEnd });
    }

    if (status) {
      queryBuilder.andWhere('booking.status = :status', { status });
