  private generateRoomCode(id: number): string {
    // Generate code format: R + id (minimum 6 digits)
    const paddedId = id.toString().padStart(6, '0');
    return `R${paddedId}`;
  }

  async findAllPaginated(params: RoomQueryParamsInput): Promise<HttpPaginatedResponse<Room>> {
    const { page = 1, size = 10, searchText: search, sortBy, sortDirection, hotelId, ownerId } = params;

    const skip = (page - 1) * size;

    const qb = this.roomRepo
      .createQueryBuilder('room')
      .leftJoinAndSelect('room.files', 'files')
      .leftJoinAndSelect('room.amenities', 'amenities')
      .leftJoinAndSelect('room.hotel', 'hotel');

    if (search) {
      qb.andWhere('(room.localName ILIKE :search OR room.code ILIKE :search)', { search: `%${search}%` });
    }

    if (hotelId) {
      qb.andWhere('room.hotelId = :hotelId', { hotelId });
    }

    if (ownerId) {
      qb.andWhere('room.ownerId = :ownerId', { ownerId });
    }

    qb.orderBy(`room.${sortBy}`, sortDirection).skip(skip).take(size);

    const [items, total] = await qb.getManyAndCount();

    return new HttpPaginatedResponse<Room>()
      .withItems(items)
      .withTotal(total)
      .withPage(page)
      .withSize(size)
      .withSortBy(sortBy)
      .withSortDirection(sortDirection);
  }

